13	// JWTAuth returns middleware that validates JWT tokens from the Authorization
14	// header. Public routes are skipped based on the provided list.
15	func JWTAuth(authService *auth.Service, publicPaths []string) echo.MiddlewareFunc {
16		publicSet := make(map[string]bool, len(publicPaths))
17		for _, p := range publicPaths {
18			publicSet[p] = true
19		}
20	
21		return func(next echo.HandlerFunc) echo.HandlerFunc {
22			return func(c echo.Context) error {
23				path := c.Request().URL.Path
24	
25				// Skip auth for public routes.
26				if publicSet[path] {
27					return next(c)
28				}
29	
30				// Also skip if the path has a public prefix (e.g., /api/v1/auth/).
31				for p := range publicSet {
32					if strings.HasSuffix(p, "*") && strings.HasPrefix(path, strings.TrimSuffix(p, "*")) {
33						return next(c)
34					}
35				}
36	
37				// Extract token from Authorization header.
38				header := c.Request().Header.Get("Authorization")
39				if header == "" {
40					return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "missing authorization header")
41				}
42	
43				parts := strings.SplitN(header, " ", 2)
44				if len(parts) != 2 || !strings.EqualFold(parts[0], "bearer") {
45					return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "invalid authorization header format")
46				}
47	
48				token := parts[1]
49				claims, err := authService.ValidateToken(token)
50				if err != nil {
51					return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "invalid or expired token")
52				}
53	
54				// Set user info in context.
55				c.Set(common.ContextKeyUserID, claims.UserID)
56				c.Set(common.ContextKeyEmail, claims.Email)
57				c.Set(common.ContextKeyRoles, claims.Roles)
58	
59				return next(c)
60			}
61		}
62	}
