11	// Handler holds auth-related HTTP handlers.
12	type Handler struct {
13		service *Service
14	}
15	
16	// NewHandler creates a new auth handler.
17	func NewHandler(service *Service) *Handler {
18		return &Handler{service: service}
19	}
20	
21	// LoginRequest represents the login request body.
22	type LoginRequest struct {
23		Email    string `json:"email"`
24		Password string `json:"password"`
25	}
26	
27	// RegisterRoutes registers auth routes on the given Echo group.
28	func (h *Handler) RegisterRoutes(g *echo.Group) {
29		g.POST("/login", h.Login)
30		g.POST("/logout", h.Logout)
31		g.GET("/me", h.Me)
32	}
33	
34	// Login handles POST /api/v1/auth/login.
35	func (h *Handler) Login(c echo.Context) error {
36		var req LoginRequest
37		if err := c.Bind(&req); err != nil {
38			return common.Error(c, http.StatusBadRequest, "BAD_REQUEST", "invalid request body")
39		}
40	
41		if req.Email == "" || req.Password == "" {
42			return common.ValidationError(c, map[string]string{
43				"email":    "email is required",
44				"password": "password is required",
45			})
46		}
47	
48		token, err := h.service.Login(c.Request().Context(), req.Email, req.Password)
49		if err != nil {
50			return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "invalid email or password")
51		}
52	
53		return common.Success(c, map[string]string{
54			"token": token,
55		})
56	}
57	
58	// Logout handles POST /api/v1/auth/logout.
59	// In a stateless JWT setup this is a no-op on the server side.
60	// Clients should discard the token.
61	func (h *Handler) Logout(c echo.Context) error {
62		return common.Success(c, map[string]string{
63			"message": "logged out successfully",
64		})
65	}
66	
67	// Me handles GET /api/v1/auth/me.
68	func (h *Handler) Me(c echo.Context) error {
69		userID := common.GetUserID(c)
70		if userID == "" {
71			return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "not authenticated")
72		}
73	
74		user, err := h.service.GetUserByID(c.Request().Context(), userID)
75		if err != nil {
76			return common.Error(c, http.StatusNotFound, "NOT_FOUND", "user not found")
77		}
78	
79		return common.Success(c, user)
80	}
