5	// DomainError represents a business-logic error with a machine-readable code.
6	type DomainError struct {
7		Code    string
8		Message string
9		Err     error
10	}
11	
12	func (e *DomainError) Error() string {
13		if e.Err != nil {
14			return fmt.Sprintf("%s: %s: %v", e.Code, e.Message, e.Err)
15		}
16		return fmt.Sprintf("%s: %s", e.Code, e.Message)
17	}
18	
19	func (e *DomainError) Unwrap() error {
20		return e.Err
21	}
22	
23	// Predefined error codes.
24	const (
25		ErrCodeNotFound       = "NOT_FOUND"
26		ErrCodeConflict       = "CONFLICT"
27		ErrCodeUnauthorized   = "UNAUTHORIZED"
28		ErrCodeForbidden      = "FORBIDDEN"
29		ErrCodeBadRequest     = "BAD_REQUEST"
30		ErrCodeInternal       = "INTERNAL_ERROR"
31		ErrCodeValidation     = "VALIDATION_ERROR"
32		ErrCodeRateLimited    = "RATE_LIMITED"
33		ErrCodeServiceUnavail = "SERVICE_UNAVAILABLE"
34	)
35	
36	// NewNotFoundError creates a NOT_FOUND domain error.
37	func NewNotFoundError(resource string) *DomainError {
38		return &DomainError{
39			Code:    ErrCodeNotFound,
40			Message: fmt.Sprintf("%s not found", resource),
41		}
42	}
43	
44	// NewConflictError creates a CONFLICT domain error.
45	func NewConflictError(message string) *DomainError {
46		return &DomainError{
47			Code:    ErrCodeConflict,
48			Message: message,
49		}
50	}
51	
52	// NewUnauthorizedError creates an UNAUTHORIZED domain error.
53	func NewUnauthorizedError(message string) *DomainError {
54		return &DomainError{
55			Code:    ErrCodeUnauthorized,
56			Message: message,
57		}
58	}
59	
60	// NewForbiddenError creates a FORBIDDEN domain error.
61	func NewForbiddenError(message string) *DomainError {
62		return &DomainError{
63			Code:    ErrCodeForbidden,
64			Message: message,
65		}
66	}
67	
68	// NewBadRequestError creates a BAD_REQUEST domain error.
69	func NewBadRequestError(message string) *DomainError {
70		return &DomainError{
71			Code:    ErrCodeBadRequest,
72			Message: message,
73		}
74	}
75	
76	// NewInternalError creates an INTERNAL_ERROR domain error.
77	func NewInternalError(message string, err error) *DomainError {
78		return &DomainError{
79			Code:    ErrCodeInternal,
80			Message: message,
81			Err:     err,
82		}
83	}
