1	import { useState } from "react";
2	import { useForm, useFieldArray } from "react-hook-form";
3	import { zodResolver } from "@hookform/resolvers/zod";
4	import { z } from "zod";
5	import { useNavigate } from "react-router-dom";
6	import api from "@/lib/api";
7	
8	const memberFieldSchema = z.object({
9	  key: z.string().min(1, "Key is required"),
10	  label: z.string().min(1, "Label is required"),
11	  type: z.enum(["text", "number", "email", "select", "checkbox", "date"]),
12	  required: z.boolean(),
13	  options: z.string().optional(),
14	});
15	
16	const checkpointSchema = z.object({
17	  name: z.string().min(1, "Checkpoint name is required"),
18	  description: z.string().optional(),
19	});
20	
21	const wizardSchema = z.object({
22	  title: z.string().min(1, "Title is required"),
23	  meetupDate: z
24	    .string()
25	    .min(1, "Meetup date is required")
26	    .regex(
27	      /^\d{2}\/\d{2}\/\d{4} \d{1,2}:\d{2} (AM|PM)$/,
28	      "Format: MM/DD/YYYY h:mm AM/PM",
29	    ),
30	  location: z.string().min(1, "Location is required"),
31	  checkpoints: z
32	    .array(checkpointSchema)
33	    .min(1, "At least one checkpoint is required"),
34	  notes: z.string().optional(),
35	  memberFields: z.array(memberFieldSchema),
36	});
37	
38	type WizardForm = z.infer<typeof wizardSchema>;
39	
40	const STEPS = [
41	  "Basic Details",
42	  "Meetup Date/Time",
43	  "Location",
44	  "Checkpoints",
45	  "Notes",
46	  "Member Form Config",
47	  "Review & Publish",
48	];
49	
50	export default function ItineraryWizard() {
51	  const [step, setStep] = useState(0);
52	  const [submitError, setSubmitError] = useState<string | null>(null);
53	  const navigate = useNavigate();
54	
55	  const {
56	    register,
57	    handleSubmit,
58	    control,
59	    watch,
60	    trigger,
61	    formState: { errors, isSubmitting },
62	  } = useForm<WizardForm>({
63	    resolver: zodResolver(wizardSchema),
64	    defaultValues: {
65	      title: "",
66	      meetupDate: "",
67	      location: "",
68	      checkpoints: [{ name: "", description: "" }],
69	      notes: "",
70	      memberFields: [],
71	    },
72	  });
73	
74	  const {
75	    fields: checkpointFields,
76	    append: addCheckpoint,
77	    remove: removeCheckpoint,
78	    move: moveCheckpoint,
79	  } = useFieldArray({ control, name: "checkpoints" });
80	
81	  const {
82	    fields: memberFieldFields,
83	    append: addMemberField,
84	    remove: removeMemberField,
85	  } = useFieldArray({ control, name: "memberFields" });
86	
87	  const formValues = watch();
88	
89	  const validateStep = async (): Promise<boolean> => {
90	    switch (step) {
91	      case 0:
92	        return trigger("title");
93	      case 1:
94	        return trigger("meetupDate");
95	      case 2:
96	        return trigger("location");
97	      case 3:
98	        return trigger("checkpoints");
99	      case 4:
100	        return true;
101	      case 5:
102	        return trigger("memberFields");
103	      default:
104	        return true;
105	    }
106	  };
107	
108	  const nextStep = async () => {
109	    const valid = await validateStep();
110	    if (valid && step < STEPS.length - 1) {
111	      setStep(step + 1);
112	    }
113	  };
114	
115	  const prevStep = () => {
116	    if (step > 0) setStep(step - 1);
117	  };
118	
119	  const onSubmit = async (data: WizardForm) => {
120	    try {
121	      setSubmitError(null);
122	      const { data: created } = await api.post("/itineraries", data);
123	      navigate(`/itineraries/${created.id}`);
124	    } catch {
125	      setSubmitError("Failed to create itinerary. Please try again.");
126	    }
127	  };
128	
129	  const inputClass =
130	    "w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-indigo-500 focus:outline-none focus:ring-1 focus:ring-indigo-500";
131	  const labelClass = "mb-1 block text-sm font-medium text-gray-700";
132	
133	  return (
134	    <div className="mx-auto max-w-2xl space-y-6">
135	      <div>
136	        <h1 className="text-2xl font-bold text-gray-900">Create Itinerary</h1>
137	        <p className="mt-1 text-gray-500">
138	          Step {step + 1} of {STEPS.length}: {STEPS[step]}
139	        </p>
140	      </div>
141	
142	      {/* Progress bar */}
143	      <div className="flex gap-1">
144	        {STEPS.map((_, i) => (
145	          <div
146	            key={i}
147	            className={`h-1.5 flex-1 rounded-full ${
148	              i <= step ? "bg-indigo-600" : "bg-gray-200"
149	            }`}
150	          />
151	        ))}
152	      </div>
153	
154	      <form
155	        onSubmit={handleSubmit(onSubmit)}
156	        className="rounded-xl border border-gray-200 bg-white p-6"
157	      >
158	        {submitError && (
159	          <div className="mb-4 rounded-lg bg-red-50 p-3 text-sm text-red-700">
160	            {submitError}
161	          </div>
162	        )}
163	
164	        {/* Step 1: Basic Details */}
165	        {step === 0 && (
166	          <div>
167	            <label htmlFor="title" className={labelClass}>
168	              Title
169	            </label>
170	            <input
171	              id="title"
172	              {...register("title")}
173	              className={inputClass}
174	              placeholder="Enter itinerary title"
175	            />
176	            {errors.title && (
177	              <p className="mt-1 text-xs text-red-600">
178	                {errors.title.message}
179	              </p>
180	            )}
181	          </div>
182	        )}
183	
184	        {/* Step 2: Meetup Date/Time */}
185	        {step === 1 && (
186	          <div>
187	            <label htmlFor="meetupDate" className={labelClass}>
188	              Meetup Date & Time
189	            </label>
190	            <input
191	              id="meetupDate"
192	              {...register("meetupDate")}
193	              className={inputClass}
194	              placeholder="MM/DD/YYYY h:mm AM"
195	            />
196	            <p className="mt-1 text-xs text-gray-400">
197	              Format: MM/DD/YYYY h:mm AM/PM (e.g. 01/15/2026 9:00 AM)
198	            </p>
199	            {errors.meetupDate && (
200	              <p className="mt-1 text-xs text-red-600">
201	                {errors.meetupDate.message}
202	              </p>
203	            )}
204	          </div>
205	        )}
206	
207	        {/* Step 3: Location */}
208	        {step === 2 && (
209	          <div>
210	            <label htmlFor="location" className={labelClass}>
211	              Location
212	            </label>
213	            <input
214	              id="location"
215	              {...register("location")}
216	              className={inputClass}
217	              placeholder="Enter meetup location"
218	            />
219	            {errors.location && (
220	              <p className="mt-1 text-xs text-red-600">
221	                {errors.location.message}
222	              </p>
223	            )}
224	          </div>
225	        )}
226	
227	        {/* Step 4: Checkpoints */}
228	        {step === 3 && (
229	          <div className="space-y-4">
230	            {checkpointFields.map((field, index) => (
231	              <div
232	                key={field.id}
233	                className="rounded-lg border border-gray-200 p-4"
234	              >
235	                <div className="mb-2 flex items-center justify-between">
236	                  <span className="text-sm font-medium text-gray-700">
237	                    Checkpoint {index + 1}
238	                  </span>
239	                  <div className="flex gap-1">
240	                    {index > 0 && (
241	                      <button
242	                        type="button"
243	                        onClick={() => moveCheckpoint(index, index - 1)}
244	                        className="rounded px-2 py-1 text-xs text-gray-500 hover:bg-gray-100"
245	                      >
246	                        Up
247	                      </button>
248	                    )}
249	                    {index < checkpointFields.length - 1 && (
250	                      <button
251	                        type="button"
252	                        onClick={() => moveCheckpoint(index, index + 1)}
253	                        className="rounded px-2 py-1 text-xs text-gray-500 hover:bg-gray-100"
254	                      >
255	                        Down
256	                      </button>
257	                    )}
258	                    {checkpointFields.length > 1 && (
259	                      <button
260	                        type="button"
261	                        onClick={() => removeCheckpoint(index)}
262	                        className="rounded px-2 py-1 text-xs text-red-500 hover:bg-red-50"
263	                      >
264	                        Remove
265	                      </button>
266	                    )}
267	                  </div>
268	                </div>
269	                <input
270	                  {...register(`checkpoints.${index}.name`)}
271	                  className={inputClass}
272	                  placeholder="Checkpoint name"
273	                />
274	                {errors.checkpoints?.[index]?.name && (
275	                  <p className="mt-1 text-xs text-red-600">
276	                    {errors.checkpoints[index]?.name?.message}
277	                  </p>
278	                )}
279	                <input
280	                  {...register(`checkpoints.${index}.description`)}
281	                  className={`${inputClass} mt-2`}
282	                  placeholder="Description (optional)"
283	                />
284	              </div>
285	            ))}
286	            <button
287	              type="button"
288	              onClick={() => addCheckpoint({ name: "", description: "" })}
289	              className="w-full rounded-lg border-2 border-dashed border-gray-300 py-2 text-sm text-gray-500 hover:border-indigo-400 hover:text-indigo-600"
290	            >
291	              + Add Checkpoint
292	            </button>
293	          </div>
294	        )}
295	
296	        {/* Step 5: Notes */}
297	        {step === 4 && (
298	          <div>
299	            <label htmlFor="notes" className={labelClass}>
300	              Notes
301	            </label>
302	            <textarea
303	              id="notes"
304	              {...register("notes")}
305	              className={`${inputClass} min-h-[120px]`}
306	              placeholder="Additional notes (optional)"
307	            />
308	          </div>
309	        )}
310	
311	        {/* Step 6: Member Form Config */}
312	        {step === 5 && (
313	          <div className="space-y-4">
314	            <p className="text-sm text-gray-500">
315	              Configure fields that members must fill out when joining.
316	            </p>
317	            {memberFieldFields.map((field, index) => (
318	              <div
319	                key={field.id}
320	                className="rounded-lg border border-gray-200 p-4"
321	              >
322	                <div className="mb-2 flex items-center justify-between">
323	                  <span className="text-sm font-medium text-gray-700">
324	                    Field {index + 1}
325	                  </span>
326	                  <button
327	                    type="button"
328	                    onClick={() => removeMemberField(index)}
329	                    className="rounded px-2 py-1 text-xs text-red-500 hover:bg-red-50"
330	                  >
331	                    Remove
332	                  </button>
333	                </div>
334	                <div className="grid grid-cols-2 gap-2">
335	                  <div>
336	                    <input
337	                      {...register(`memberFields.${index}.key`)}
338	                      className={inputClass}
339	                      placeholder="Key (e.g. phone)"
340	                    />
341	                    {errors.memberFields?.[index]?.key && (
342	                      <p className="mt-1 text-xs text-red-600">
343	                        {errors.memberFields[index]?.key?.message}
344	                      </p>
345	                    )}
346	                  </div>
347	                  <div>
348	                    <input
349	                      {...register(`memberFields.${index}.label`)}
350	                      className={inputClass}
351	                      placeholder="Label (e.g. Phone Number)"
352	                    />
353	                    {errors.memberFields?.[index]?.label && (
354	                      <p className="mt-1 text-xs text-red-600">
355	                        {errors.memberFields[index]?.label?.message}
356	                      </p>
357	                    )}
358	                  </div>
359	                  <select
360	                    {...register(`memberFields.${index}.type`)}
361	                    className={inputClass}
362	                  >
363	                    <option value="text">Text</option>
364	                    <option value="number">Number</option>
365	                    <option value="email">Email</option>
366	                    <option value="select">Select</option>
367	                    <option value="checkbox">Checkbox</option>
368	                    <option value="date">Date</option>
369	                  </select>
370	                  <label className="flex items-center gap-2 text-sm text-gray-700">
371	                    <input
372	                      type="checkbox"
373	                      {...register(`memberFields.${index}.required`)}
374	                      className="rounded border-gray-300"
375	                    />
376	                    Required
377	                  </label>
378	                </div>
379	                <input
380	                  {...register(`memberFields.${index}.options`)}
381	                  className={`${inputClass} mt-2`}
382	                  placeholder="Options (comma-separated, for select type)"
383	                />
384	              </div>
385	            ))}
386	            <button
387	              type="button"
388	              onClick={() =>
389	                addMemberField({
390	                  key: "",
391	                  label: "",
392	                  type: "text",
393	                  required: false,
394	                  options: "",
395	                })
396	              }
397	              className="w-full rounded-lg border-2 border-dashed border-gray-300 py-2 text-sm text-gray-500 hover:border-indigo-400 hover:text-indigo-600"
398	            >
399	              + Add Field
400	            </button>
401	          </div>
402	        )}
403	
404	        {/* Step 7: Review */}
405	        {step === 6 && (
406	          <div className="space-y-4">
407	            <h3 className="font-semibold text-gray-900">Review</h3>
408	            <div className="space-y-3 text-sm">
