416	                </span>{" "}
417	                {formValues.meetupDate}
418	              </div>
419	              <div>
420	                <span className="font-medium text-gray-700">Location:</span>{" "}
421	                {formValues.location}
422	              </div>
423	              <div>
424	                <span className="font-medium text-gray-700">
425	                  Checkpoints:
426	                </span>{" "}
427	                {formValues.checkpoints?.length ?? 0}
428	                <ul className="ml-4 mt-1 list-disc text-gray-500">
429	                  {formValues.checkpoints?.map((cp, i) => (
430	                    <li key={i}>{cp.name || "(unnamed)"}</li>
431	                  ))}
432	                </ul>
433	              </div>
434	              {formValues.notes && (
435	                <div>
436	                  <span className="font-medium text-gray-700">Notes:</span>{" "}
437	                  {formValues.notes}
438	                </div>
439	              )}
440	              <div>
441	                <span className="font-medium text-gray-700">
442	                  Member Fields:
443	                </span>{" "}
444	                {formValues.memberFields?.length ?? 0}
445	                {(formValues.memberFields?.length ?? 0) > 0 && (
446	                  <ul className="ml-4 mt-1 list-disc text-gray-500">
447	                    {formValues.memberFields?.map((f, i) => (
448	                      <li key={i}>
