451	                      </li>
452	                    ))}
453	                  </ul>
454	                )}
455	              </div>
456	            </div>
457	          </div>
458	        )}
459	
460	        {/* Navigation */}
461	        <div className="mt-6 flex justify-between">
462	          <button
463	            type="button"
464	            onClick={prevStep}
465	            disabled={step === 0}
