{"file_path": "/c/Users/yonim/w2t80/repo/apps/api/internal/modules/risk/service.go", "content": "package risk

import (
	"context"
	"encoding/json"
	"fmt"

	"go.uber.org/zap"
)

// Service handles risk business logic.
type Service struct {
	repo   *Repository
	engine *Engine
	logger *zap.Logger
}

// NewService creates a new risk service.
func NewService(repo *Repository, logger *zap.Logger) *Service {
	return &Service{
		repo:   repo,
		engine: NewEngine(repo, logger),
		logger: logger,
	}
}

// RiskSummary is the response for a user's risk profile.
type RiskSummary struct {
	UserID           string           `json:"user_id"`
	IsBlacklisted    bool             `json:"is_blacklisted"`
	BlacklistReason  string           `json:"blacklist_reason,omitempty"`
	RiskScore        *float64         `json:"risk_score,omitempty"`
	ActiveThrottles  []ThrottleAction `json:"active_throttles"`
	HarassmentFlags  int              `json:"harassment_flags"`
}

// GetRiskSummary returns a comprehensive risk profile for a user.
func (s *Service) GetRiskSummary(ctx context.Context, userID string) (*RiskSummary, error) {
	summary := &RiskSummary{UserID: userID}

	bl, err := s.repo.GetBlacklist(ctx, userID)
	if err != nil {
		return nil, err
	}
	if bl != nil {
		summary.IsBlacklisted = true
		summary.BlacklistReason = bl.Reason
	}

	rs, err := s.repo.GetRiskScore(ctx, userID)
	if err != nil {
		return nil, err
	}
	if rs != nil {
		summary.RiskScore = &rs.Score
	}

	throttles, err := s.repo.GetActiveThrottles(ctx, userID)
	if err != nil {
		return nil, err
	}
	summary.ActiveThrottles = throttles

	flags, err := s.repo.CountHarassmentFlags(ctx, userID)
	if err != nil {
		return nil, err
	}
	summary.HarassmentFlags = flags

	return summary, nil
}

// EvaluateAction checks risk for a user action.
func (s *Service) EvaluateAction(ctx context.Context, userID, actionType string) (*RiskDecision, error) {
	return s.engine.EvaluateAction(ctx, userID, actionType)
}

// RecordEvent records a risk event and evaluates.
func (s *Service) RecordEvent(ctx context.Context, userID, eventType, description, severity string) error {
	metadata, _ := json.Marshal(map[string]string{"severity": severity})
	return s.repo.CreateRiskEvent(ctx, RiskEvent{
		UserID:       userID,
		EventType:    eventType,
		Description:  description,
		Severity:     severity,
		MetadataJSON: metadata,
	})
}

// BlacklistUser blacklists a user.
func (s *Service) BlacklistUser(ctx context.Context, targetID, adminID, reason string) error {
	if reason == "" {
		return fmt.Errorf("reason is required")
	}
	return s.repo.BlacklistUser(ctx, targetID, adminID, reason)
}

// UnblacklistUser removes a blacklist.
func (s *Service) UnblacklistUser(ctx context.Context, targetID string) error {
	return s.repo.UnblacklistUser(ctx, targetID)
}

// GetPendingApprovals returns pending admin approvals.
func (s *Service) GetPendingApprovals(ctx context.Context) ([]AdminApproval, error) {
	return s.repo.GetPendingApprovals(ctx)
}

// ResolveApproval resolves an admin approval.
func (s *Service) ResolveApproval(ctx context.Context, id, adminID, status, notes string) error {
	if status != "approved" && status != "rejected" {
		return fmt.Errorf("status must be 'approved' or 'rejected'")
	}
	return s.repo.ResolveApproval(ctx, id, adminID, status, notes)
}
"}

