	}
	return s.repo.BlacklistUser(ctx, targetID, adminID, reason)
}

// UnblacklistUser removes a blacklist.
func (s *Service) UnblacklistUser(ctx context.Context, targetID string) error {
	return s.repo.UnblacklistUser(ctx, targetID)
}

// GetPendingApprovals returns pending admin approvals.
func (s *Service) GetPendingApprovals(ctx context.Context) ([]AdminApproval, error) {
	return s.repo.GetPendingApprovals(ctx)
}

// ResolveApproval resolves an admin approval.
func (s *Service) ResolveApproval(ctx context.Context, id, adminID, status, notes string) error {
	if status != "approved" && status != "rejected" {
		return fmt.Errorf("status must be 'approved' or 'rejected'")
	}
	return s.repo.ResolveApproval(ctx, id, adminID, status, notes)
}
"}

