import (
	"context"
	"time"

	"go.uber.org/zap"
)

// Engine evaluates risk for user actions.
type Engine struct {
	repo   *Repository
	logger *zap.Logger
}

// NewEngine creates a new risk engine.
func NewEngine(repo *Repository, logger *zap.Logger) *Engine {
	return &Engine{repo: repo, logger: logger}
}

// EvaluateAction checks if a user can perform an action based on risk rules.
func (e *Engine) EvaluateAction(ctx context.Context, userID, actionType string) (*RiskDecision, error) {
	// Check blacklist first.
	bl, err := e.repo.GetBlacklist(ctx, userID)
	if err != nil {
		return nil, err
	}
	if bl != nil {
		return &RiskDecision{Action: "deny", Reason: "account is blacklisted: " + bl.Reason}, nil
	}

	// Check active throttles.
	throttled, err := e.repo.IsThrottled(ctx, userID, actionType)
	if err != nil {
		return nil, err
	}
	if throttled {
		return &RiskDecision{Action: "deny", Reason: "action is currently throttled"}, nil
	}

	// Heuristic: >8 cancellations in 24 hours.
	cancellations, err := e.repo.CountCancellationsInWindow(ctx, userID, 24)
	if err != nil {
		e.logger.Error("failed to count cancellations", zap.Error(err))
	} else if cancellations > 8 {
		_ = e.repo.CreateThrottle(ctx, ThrottleAction{
			UserID:     userID,
			ActionType: actionType,
			Reason:     "exceeded 8 cancellations in 24 hours",
			ExpiresAt:  time.Now().Add(6 * time.Hour),
		})
		return &RiskDecision{Action: "require_approval", Reason: "too many cancellations in 24 hours"}, nil
	}

	// Heuristic: 20 RFQs in 10 minutes.
	if actionType == "create_rfq" {
		rfqCount, err := e.repo.CountRFQsInWindow(ctx, userID, 10)
		if err != nil {
			e.logger.Error("failed to count RFQs", zap.Error(err))
		} else if rfqCount >= 20 {
			_ = e.repo.CreateThrottle(ctx, ThrottleAction{
				UserID:     userID,
				ActionType: "create_rfq",
				Reason:     "exceeded 20 RFQs in 10 minutes",
				ExpiresAt:  time.Now().Add(1 * time.Hour),
			})
			return &RiskDecision{Action: "deny", Reason: "too many RFQ requests"}, nil
		}
	}

	// Heuristic: repeated harassment flags (>=3).
	flags, err := e.repo.CountHarassmentFlags(ctx, userID)
	if err != nil {
		e.logger.Error("failed to count harassment flags", zap.Error(err))
	} else if flags >= 3 {
		_ = e.repo.CreateThrottle(ctx, ThrottleAction{
			UserID:     userID,
			ActionType: "*",
			Reason:     "multiple harassment flags",
			ExpiresAt:  time.Now().Add(24 * time.Hour),
		})
		return &RiskDecision{Action: "deny", Reason: "account frozen due to multiple harassment reports"}, nil
	}

	return &RiskDecision{Action: "allow"}, nil
}
"}

