107		if errors.As(err, &domainErr) {
108			switch domainErr.Code {
109			case common.ErrCodeNotFound:
110				return common.Error(c, http.StatusNotFound, domainErr.Code, domainErr.Message)
111			case common.ErrCodeForbidden:
112				return common.Error(c, http.StatusForbidden, domainErr.Code, domainErr.Message)
113			case common.ErrCodeBadRequest:
114				return common.Error(c, http.StatusBadRequest, domainErr.Code, domainErr.Message)
115			default:
116				h.logger.Error("domain error", zap.String("code", domainErr.Code), zap.Error(err))
117				return common.Error(c, http.StatusInternalServerError, common.ErrCodeInternal, "internal server error")
118			}
119		}
