243	func (h *Handler) handleError(c echo.Context, err error) error {
244		var domainErr *common.DomainError
245		if errors.As(err, &domainErr) {
246			switch domainErr.Code {
247			case common.ErrCodeNotFound:
248				return common.Error(c, http.StatusNotFound, domainErr.Code, domainErr.Message)
249			case common.ErrCodeForbidden:
250				return common.Error(c, http.StatusForbidden, domainErr.Code, domainErr.Message)
251			case common.ErrCodeConflict:
252				return common.Error(c, http.StatusConflict, domainErr.Code, domainErr.Message)
253			case common.ErrCodeBadRequest:
254				return common.Error(c, http.StatusBadRequest, domainErr.Code, domainErr.Message)
255			case common.ErrCodeValidation:
256				return common.Error(c, http.StatusUnprocessableEntity, domainErr.Code, domainErr.Message)
257			default:
258				h.logger.Error("domain error", zap.String("code", domainErr.Code), zap.Error(err))
259				return common.Error(c, http.StatusInternalServerError, common.ErrCodeInternal, "internal server error")
260			}
261		}
262		h.logger.Error("unhandled error", zap.Error(err))
263		return common.Error(c, http.StatusInternalServerError, common.ErrCodeInternal, "internal server error")
264	}
