77			tokenStart := idx + len(prefix)
78			if tokenStart < len(path) {
79				return path[:tokenStart] + "[REDACTED]"
80			}
81		}
82		return path
83	}
84	
85	// maskQueryParams masks sensitive query parameter values.
86	func maskQueryParams(raw string) string {
87		if raw == "" {
88			return ""
89		}
90	
91		pairs := strings.Split(raw, "&")
92		for i, pair := range pairs {
93			parts := strings.SplitN(pair, "=", 2)
94			if len(parts) == 2 && sensitiveQueryParams[strings.ToLower(parts[0])] {
95				pairs[i] = parts[0] + "=***"
96			}
97		}
98		return strings.Join(pairs, "&")
99	}
