	tokenStr, _ := token.SignedString([]byte(secret))

	svc := &Service{
		jwtSecret: []byte(secret),
		tokenTTL:  1 * time.Hour,
	}

	_, err := svc.ValidateToken(tokenStr)
	if err == nil {
		t.Error("should reject expired token")
	}
}

func TestValidateToken_GarbageInput(t *testing.T) {
	svc := &Service{
		jwtSecret: []byte("secret"),
		tokenTTL:  1 * time.Hour,
	}

