109	// GetFilesForRecord returns all files linked to a given record.
110	func (h *Handler) GetFilesForRecord(c echo.Context) error {
111		userID := common.GetUserID(c)
112		if userID == "" {
113			return common.Error(c, http.StatusUnauthorized, "UNAUTHORIZED", "authentication required")
114		}
115	
116		recordType := c.Param("recordType")
117		recordID := c.Param("recordId")
118	
119		if recordType == "" || recordID == "" {
120			return common.Error(c, http.StatusBadRequest, "BAD_REQUEST", "recordType and recordId are required")
121		}
122	
123		roles := common.GetRoles(c)
124		files, err := h.service.GetFilesForRecord(c.Request().Context(), recordType, recordID, userID, roles)
125		if err != nil {
126			return handleServiceError(c, err)
127		}
128	
129		if files == nil {
130			files = []FileMetadata{}
131		}
132	
133		return common.Success(c, files)
134	}
