136	// handleServiceError maps domain errors to HTTP responses.
137	func handleServiceError(c echo.Context, err error) error {
138		if de, ok := err.(*common.DomainError); ok {
139			switch de.Code {
140			case common.ErrCodeNotFound:
141				return common.Error(c, http.StatusNotFound, de.Code, de.Message)
142			case common.ErrCodeForbidden:
143				return common.Error(c, http.StatusForbidden, de.Code, de.Message)
144			case common.ErrCodeConflict:
145				return common.Error(c, http.StatusConflict, de.Code, de.Message)
146			case common.ErrCodeBadRequest:
147				return common.Error(c, http.StatusBadRequest, de.Code, de.Message)
148			case common.ErrCodeValidation:
149				return common.Error(c, http.StatusUnprocessableEntity, de.Code, de.Message)
150			}
151		}
152		return common.Error(c, http.StatusInternalServerError, "INTERNAL_ERROR", "an unexpected error occurred")
153	}
