408	func (s *Service) ListBookings(ctx context.Context, userID string, page, pageSize int) (map[string]interface{}, error) {
409		if page < 1 {
410			page = 1
411		}
412		if pageSize < 1 || pageSize > 100 {
413			pageSize = 20
414		}
415		offset := (page - 1) * pageSize
416	
417		var total int
418		err := s.pool.QueryRow(ctx,
419			`SELECT COUNT(*) FROM bookings WHERE organizer_id = $1`, userID).Scan(&total)
420		if err != nil {
421			return nil, err
422		}
423	
424		rows, err := s.pool.Query(ctx,
425			`SELECT id, organizer_id, itinerary_id, title, description, status, total_amount, discount_amount, escrow_amount, created_at, updated_at
426			 FROM bookings WHERE organizer_id = $1 ORDER BY created_at DESC LIMIT $2 OFFSET $3`,
427			userID, pageSize, offset)
428		if err != nil {
429			return nil, err
430		}
431		defer rows.Close()
432	
433		var bookings []map[string]interface{}
434		for rows.Next() {
435			var id, organizerID, title, status string
436			var itineraryID, description *string
437			var totalAmount, discountAmount, escrowAmount float64
438			var createdAt, updatedAt time.Time
439			if err := rows.Scan(&id, &organizerID, &itineraryID, &title, &description, &status, &totalAmount, &discountAmount, &escrowAmount, &createdAt, &updatedAt); err != nil {
440				return nil, err
441			}
442			bookings = append(bookings, map[string]interface{}{
443				"id": id, "organizerId": organizerID, "itineraryId": itineraryID,
444				"title": title, "description": description, "status": status,
445				"totalAmount": totalAmount, "discountAmount": discountAmount, "escrowAmount": escrowAmount,
446				"createdAt": createdAt, "updatedAt": updatedAt,
447			})
448		}
449		if bookings == nil {
450			bookings = []map[string]interface{}{}
451		}
452	
453		return map[string]interface{}{
454			"items": bookings, "total": total, "page": page,
455			"pageSize": pageSize, "totalPages": (total + pageSize - 1) / pageSize,
456		}, rows.Err()
457	}

