## FIX 3: ItineraryWizard.tsx - fix create flow
The backend CREATE endpoint only accepts `{title, meetupAt, meetupLocationText, notes}`. It does NOT accept checkpoints or formDefinitions inline. Those must be added via separate POST calls after creation.

Read the file. Fix the onSubmit to:
1. Create the itinerary with just the base fields
2. Then POST checkpoints one by one to `/itineraries/:id/checkpoints`
3. Then POST form definitions to `/itineraries/:id/form-definitions`

```typescript
const onSubmit = async (data: WizardForm) => {
  try {
    setSubmitError(null);
    const meetupDate = new Date(data.meetupDate);

    const { data: created } = await api.post("/itineraries", {
      title: data.title,
      meetupAt: meetupDate.toISOString(),
      meetupLocationText: data.location,
      notes: data.notes || "",
    });

    const itineraryId = created.id;

    for (let i = 0; i < data.checkpoints.length; i++) {
      await api.post(`/itineraries/${itineraryId}/checkpoints`, {
        checkpointText: data.checkpoints[i].name,
        sortOrder: i + 1,
      });
    }

    for (let i = 0; i < data.memberFields.length; i++) {
      const f = data.memberFields[i];
      await api.post(`/itineraries/${itineraryId}/form-definitions`, {
        fieldKey: f.key,
        fieldLabel: f.label,
        fieldType: f.type,
        required: f.required,
        options: f.options ? JSON.stringify(f.options.split(",").map((o: string) => o.trim())) : null,
        sortOrder: i + 1,
      });
    }

    navigate(`/itineraries/${itineraryId}`);
  } catch {
    setSubmitError("Failed to create itinerary. Please try again.");
  }
};
```

